1	package com.nutriops.app.domain.usecase.config
2	
3	import com.nutriops.app.data.repository.ConfigRepository
4	import com.nutriops.app.data.repository.RolloutRepository
5	import com.nutriops.app.domain.model.Role
6	import com.nutriops.app.security.RbacManager
7	import javax.inject.Inject
8	
9	/**
10	 * Operations & Configuration Center use case:
11	 * - Homepage modules, ad slots, campaigns, coupons
12	 * - Black/whitelist, purchase limits
13	 * - Config versioning
14	 * - 10% canary rollout (deterministic assignment)
15	 */
16	class ManageConfigUseCase @Inject constructor(
17	    private val configRepository: ConfigRepository,
18	    private val rolloutRepository: RolloutRepository
19	) {
20	    // ── Config ──
21	
22	    suspend fun createConfig(key: String, value: String, actorId: String, actorRole: Role): Result<String> {
23	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CONFIG)
24	            .getOrElse { return Result.failure(it) }
25	        return configRepository.createConfig(key, value, actorId, actorRole)
26	    }
27	
28	    suspend fun updateConfig(configId: String, newValue: String, actorId: String, actorRole: Role): Result<Unit> {
29	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CONFIG)
30	            .getOrElse { return Result.failure(it) }
31	        return configRepository.updateConfig(configId, newValue, actorId, actorRole)
32	    }
33	
34	    suspend fun getAllConfigs(actorRole: Role): Result<List<com.nutriops.app.data.local.Configs>> {
35	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CONFIG)
36	            .getOrElse { return Result.failure(it) }
37	        return Result.success(configRepository.getAllConfigs())
38	    }
39	
40	    suspend fun getConfigVersions(configId: String, actorRole: Role): Result<List<com.nutriops.app.data.local.ConfigVersions>> {
41	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CONFIG)
42	            .getOrElse { return Result.failure(it) }
43	        return Result.success(configRepository.getConfigVersions(configId))
44	    }
45	
46	    // ── Homepage Modules ──
47	
48	    suspend fun createHomepageModule(
49	        name: String, moduleType: String, position: Long, configVersionId: String?,
50	        actorId: String, actorRole: Role
51	    ): Result<String> {
52	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_HOMEPAGE_MODULES)
53	            .getOrElse { return Result.failure(it) }
54	        return configRepository.createHomepageModule(name, moduleType, position, configVersionId, actorId, actorRole)
55	    }
56	
57	    suspend fun getAllHomepageModules(actorRole: Role): Result<List<com.nutriops.app.data.local.HomepageModules>> {
58	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_HOMEPAGE_MODULES)
59	            .getOrElse { return Result.failure(it) }
60	        return Result.success(configRepository.getAllHomepageModules())
61	    }
62	
63	    // ── Ad Slots ──
64	
65	    suspend fun createAdSlot(
66	        name: String, position: String, content: String, configVersionId: String?,
67	        actorId: String, actorRole: Role
68	    ): Result<String> {
69	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_AD_SLOTS)
70	            .getOrElse { return Result.failure(it) }
71	        return configRepository.createAdSlot(name, position, content, configVersionId, actorId, actorRole)
72	    }
73	
74	    suspend fun getAllAdSlots(actorRole: Role): Result<List<com.nutriops.app.data.local.AdSlots>> {
75	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_AD_SLOTS)
76	            .getOrElse { return Result.failure(it) }
77	        return Result.success(configRepository.getAllAdSlots())
78	    }
79	
80	    // ── Campaigns ──
81	
82	    suspend fun createCampaign(
83	        name: String, description: String, landingTopic: String,
84	        startDate: String, endDate: String, configVersionId: String?,
85	        actorId: String, actorRole: Role
86	    ): Result<String> {
87	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CAMPAIGNS)
88	            .getOrElse { return Result.failure(it) }
89	        return configRepository.createCampaign(name, description, landingTopic, startDate, endDate, configVersionId, actorId, actorRole)
90	    }
91	
92	    suspend fun getAllCampaigns(actorRole: Role): Result<List<com.nutriops.app.data.local.Campaigns>> {
93	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_CAMPAIGNS)
94	            .getOrElse { return Result.failure(it) }
95	        return Result.success(configRepository.getAllCampaigns())
96	    }
97	
98	    // ── Coupons ──
99	
100	    suspend fun createCoupon(
101	        code: String, description: String, discountType: String, discountValue: Double,
102	        conditionsJson: String, maxUsesPerUser: Long, periodDays: Long,
103	        configVersionId: String?, actorId: String, actorRole: Role
104	    ): Result<String> {
105	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_COUPONS)
106	            .getOrElse { return Result.failure(it) }
107	        return configRepository.createCoupon(
108	            code, description, discountType, discountValue, conditionsJson,
109	            maxUsesPerUser, periodDays, configVersionId, actorId, actorRole
110	        )
111	    }
112	
113	    suspend fun validateAndUseCoupon(couponId: String, userId: String): Result<Boolean> {
114	        val valid = configRepository.validateCouponUsage(couponId, userId).getOrElse { return Result.failure(it) }
115	        if (!valid) return Result.failure(IllegalStateException("Coupon usage limit reached"))
116	        configRepository.recordCouponUsage(couponId, userId)
117	        return Result.success(true)
118	    }
119	
120	    suspend fun getAllCoupons(actorRole: Role): Result<List<com.nutriops.app.data.local.Coupons>> {
121	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_COUPONS)
122	            .getOrElse { return Result.failure(it) }
123	        return Result.success(configRepository.getAllCoupons())
124	    }
125	
126	    // ── Black/White List ──
127	
128	    suspend fun addToBlacklist(
129	        entityType: String, entityValue: String, reason: String,
130	        actorId: String, actorRole: Role
131	    ): Result<String> {
132	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_BLACKWHITELIST)
133	            .getOrElse { return Result.failure(it) }
134	        return configRepository.addToList("BLACK", entityType, entityValue, reason, actorId, actorRole)
135	    }
136	
137	    suspend fun addToWhitelist(
138	        entityType: String, entityValue: String, reason: String,
139	        actorId: String, actorRole: Role
140	    ): Result<String> {
141	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_BLACKWHITELIST)
142	            .getOrElse { return Result.failure(it) }
143	        return configRepository.addToList("WHITE", entityType, entityValue, reason, actorId, actorRole)
144	    }
145	
146	    suspend fun isBlacklisted(entityType: String, entityValue: String) =
147	        configRepository.isBlacklisted(entityType, entityValue)
148	
149	    suspend fun getBlacklist(actorRole: Role): Result<List<com.nutriops.app.data.local.BlackWhiteList>> {
150	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_BLACKWHITELIST)
151	            .getOrElse { return Result.failure(it) }
152	        return Result.success(configRepository.getBlackWhiteList("BLACK"))
153	    }
154	
155	    suspend fun getWhitelist(actorRole: Role): Result<List<com.nutriops.app.data.local.BlackWhiteList>> {
156	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_BLACKWHITELIST)
157	            .getOrElse { return Result.failure(it) }
158	        return Result.success(configRepository.getBlackWhiteList("WHITE"))
159	    }
160	
161	    // ── Purchase Limits ──
162	
163	    suspend fun setPurchaseLimit(
164	        entityType: String, maxQuantity: Long, periodDays: Long,
165	        actorId: String, actorRole: Role
166	    ): Result<String> {
167	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_PURCHASE_LIMITS)
168	            .getOrElse { return Result.failure(it) }
169	        return configRepository.setPurchaseLimit(entityType, maxQuantity, periodDays, actorId, actorRole)
170	    }
171	
172	    suspend fun getPurchaseLimits(actorRole: Role): Result<List<com.nutriops.app.data.local.PurchaseLimits>> {
173	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_PURCHASE_LIMITS)
174	            .getOrElse { return Result.failure(it) }
175	        return Result.success(configRepository.getPurchaseLimits())
176	    }
177	
178	    // ── Canary Rollout ──
179	
180	    suspend fun startCanaryRollout(
181	        configVersionId: String, canaryPercentage: Int, actorId: String, actorRole: Role
182	    ): Result<String> {
183	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_ROLLOUTS)
184	            .getOrElse { return Result.failure(it) }
185	        return rolloutRepository.createRollout(configVersionId, canaryPercentage, actorId, actorRole)
186	    }
187	
188	    suspend fun promoteRollout(rolloutId: String, actorId: String, actorRole: Role): Result<Unit> {
189	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_ROLLOUTS)
190	            .getOrElse { return Result.failure(it) }
191	        return rolloutRepository.promoteToFull(rolloutId, actorId, actorRole)
192	    }
193	
194	    suspend fun rollbackRollout(rolloutId: String, actorId: String, actorRole: Role): Result<Unit> {
195	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_ROLLOUTS)
196	            .getOrElse { return Result.failure(it) }
197	        return rolloutRepository.rollback(rolloutId, actorId, actorRole)
198	    }
199	
200	    suspend fun getActiveRollout(actorRole: Role): Result<com.nutriops.app.data.local.Rollouts?> {
201	        RbacManager.checkPermission(actorRole, RbacManager.Permission.MANAGE_ROLLOUTS)
202	            .getOrElse { return Result.failure(it) }
203	        return Result.success(rolloutRepository.getActiveRollout())
204	    }
205	
206	    fun isUserInCanary(userId: String, rolloutId: String) =
207	        rolloutRepository.isUserInCanary(userId, rolloutId)
208	}
