28	data class UserUiItem(val id: String, val username: String, val role: String, val isActive: Boolean, val isLocked: Boolean)
29	
30	@HiltViewModel
31	class AdminUsersViewModel @Inject constructor(
32	    private val userRepository: UserRepository,
33	    private val authManager: AuthManager
34	) : ViewModel() {
35	
36	    private val _users = MutableStateFlow<List<UserUiItem>>(emptyList())
37	    val users: StateFlow<List<UserUiItem>> = _users.asStateFlow()
38	    private val _message = MutableStateFlow<String?>(null)
39	    val message: StateFlow<String?> = _message.asStateFlow()
40	
41	    init { loadUsers() }
42	
43	    fun loadUsers() {
44	        viewModelScope.launch {
45	            val all = userRepository.getAllUsers()
46	            _users.value = all.map { UserUiItem(it.id, it.username, it.role, it.isActive == 1L, it.isLocked == 1L) }
47	        }
48	    }
49	
50	    fun createUser(username: String, password: String, role: Role) {
51	        viewModelScope.launch {
52	            val session = authManager.currentSession.value ?: return@launch
53	            userRepository.createUser(username, password, role, session.userId, session.role)
54	                .onSuccess { _message.value = "User created: $username"; loadUsers() }
55	                .onFailure { _message.value = "Error: ${it.message}" }
56	        }
57	    }
58	}
59	
60	@OptIn(ExperimentalMaterial3Api::class)
61	@Composable
62	fun AdminUsersScreen(
63	    onBack: () -> Unit,
64	    viewModel: AdminUsersViewModel = hiltViewModel()
65	) {
66	    val users by viewModel.users.collectAsState()
67	    var showCreateDialog by remember { mutableStateOf(false) }
68	
69	    Scaffold(
70	        topBar = {
71	            TopAppBar(
72	                title = { Text("User Management") },
73	                navigationIcon = { IconButton(onClick = onBack) { Icon(Icons.AutoMirrored.Filled.ArrowBack, "Back") } }
74	            )
75	        },
76	        floatingActionButton = {
77	            FloatingActionButton(onClick = { showCreateDialog = true }) { Icon(Icons.Default.PersonAdd, "Add User") }
78	        }
79	    ) { padding ->
80	        LazyColumn(modifier = Modifier.fillMaxSize().padding(padding).padding(16.dp), verticalArrangement = Arrangement.spacedBy(8.dp)) {
81	            items(users) { user ->
82	                Card(modifier = Modifier.fillMaxWidth()) {
83	                    Row(modifier = Modifier.padding(16.dp).fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
84	                        Column {
85	                            Text(user.username, style = MaterialTheme.typography.titleSmall)
86	                            Text("ID: ${user.id.take(8)}...", style = MaterialTheme.typography.labelSmall)
87	                        }
88	                        Column(horizontalAlignment = androidx.compose.ui.Alignment.End) {
89	                            StatusChip(user.role, MaterialTheme.colorScheme.primary)
90	                            if (user.isLocked) StatusChip("LOCKED", MaterialTheme.colorScheme.error)
91	                            if (!user.isActive) StatusChip("INACTIVE", MaterialTheme.colorScheme.onSurfaceVariant)
92	                        }
93	                    }
94	                }
95	            }
96	        }
97	    }
98	
99	    if (showCreateDialog) {
100	        var username by remember { mutableStateOf("") }
101	        var password by remember { mutableStateOf("") }
102	        var selectedRole by remember { mutableStateOf(Role.END_USER) }
103	        AlertDialog(
104	            onDismissRequest = { showCreateDialog = false },
105	            title = { Text("Create User") },
106	            text = {
107	                Column {
108	                    OutlinedTextField(value = username, onValueChange = { username = it }, label = { Text("Username") }, modifier = Modifier.fillMaxWidth())
109	                    Spacer(modifier = Modifier.height(8.dp))
110	                    OutlinedTextField(value = password, onValueChange = { password = it }, label = { Text("Password") }, modifier = Modifier.fillMaxWidth())
111	                    Spacer(modifier = Modifier.height(8.dp))
112	                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
113	                        Role.entries.forEach { role ->
114	                            FilterChip(selected = selectedRole == role, onClick = { selectedRole = role }, label = { Text(role.name.take(5)) })
115	                        }
116	                    }
117	                }
118	            },
119	            confirmButton = { Button(onClick = { viewModel.createUser(username, password, selectedRole); showCreateDialog = false }) { Text("Create") } },
120	            dismissButton = { TextButton(onClick = { showCreateDialog = false }) { Text("Cancel") } }
121	        )
122	    }
123	}
