18	object Routes {
19	    const val LOGIN = "login"
20	    const val BOOTSTRAP = "bootstrap"
21	    const val ADMIN_DASHBOARD = "admin/dashboard"
22	    const val ADMIN_CONFIG = "admin/config"
23	    const val ADMIN_RULES = "admin/rules"
24	    const val ADMIN_ROLLOUTS = "admin/rollouts"
25	    const val ADMIN_USERS = "admin/users"
26	    const val ADMIN_AUDIT = "admin/audit"
27	    const val AGENT_DASHBOARD = "agent/dashboard"
28	    const val AGENT_TICKETS = "agent/tickets"
29	    const val AGENT_TICKET_DETAIL = "agent/ticket/{ticketId}"
30	    const val USER_DASHBOARD = "user/dashboard"
31	    const val USER_PROFILE = "user/profile"
32	    const val USER_MEAL_PLAN = "user/mealplan"
33	    const val USER_LEARNING_PLANS = "user/learningplans"
34	    const val USER_MESSAGES = "user/messages"
35	    const val USER_TICKETS = "user/tickets"
36	}
