38	@Composable
39	fun NutriOpsNavHost(
40	    navController: NavHostController = rememberNavController()
41	) {
42	    val authViewModel: AuthViewModel = hiltViewModel()
43	    val authState by authViewModel.uiState.collectAsState()
44	
45	    val startDestination = when {
46	        authState.needsBootstrap -> Routes.BOOTSTRAP
47	        authState.isAuthenticated -> when (authState.role) {
48	            "ADMINISTRATOR" -> Routes.ADMIN_DASHBOARD
49	            "AGENT" -> Routes.AGENT_DASHBOARD
50	            else -> Routes.USER_DASHBOARD
51	        }
52	        else -> Routes.LOGIN
53	    }
54	
55	    NavHost(navController = navController, startDestination = startDestination) {
56	        // ── Auth ──
57	        composable(Routes.LOGIN) {
58	            LoginScreen(
59	                viewModel = authViewModel,
60	                onLoginSuccess = { role ->
61	                    val dest = when (role) {
62	                        "ADMINISTRATOR" -> Routes.ADMIN_DASHBOARD
63	                        "AGENT" -> Routes.AGENT_DASHBOARD
64	                        else -> Routes.USER_DASHBOARD
65	                    }
66	                    navController.navigate(dest) { popUpTo(Routes.LOGIN) { inclusive = true } }
67	                },
68	                onNeedsBootstrap = {
69	                    navController.navigate(Routes.BOOTSTRAP) { popUpTo(Routes.LOGIN) { inclusive = true } }
70	                }
71	            )
72	        }
73	
74	        composable(Routes.BOOTSTRAP) {
75	            BootstrapScreen(
76	                viewModel = authViewModel,
77	                onBootstrapSuccess = {
78	                    navController.navigate(Routes.ADMIN_DASHBOARD) { popUpTo(0) { inclusive = true } }
79	                }
80	            )
81	        }
82	
83	        // ── Administrator ──
84	        composable(Routes.ADMIN_DASHBOARD) {
85	            AdminDashboardScreen(
86	                onNavigateToConfig = { navController.navigate(Routes.ADMIN_CONFIG) },
87	                onNavigateToRules = { navController.navigate(Routes.ADMIN_RULES) },
88	                onNavigateToRollouts = { navController.navigate(Routes.ADMIN_ROLLOUTS) },
89	                onNavigateToUsers = { navController.navigate(Routes.ADMIN_USERS) },
90	                onNavigateToAudit = { navController.navigate(Routes.ADMIN_AUDIT) },
91	                onLogout = {
92	                    authViewModel.logout()
93	                    navController.navigate(Routes.LOGIN) { popUpTo(0) { inclusive = true } }
94	                }
95	            )
96	        }
97	
98	        composable(Routes.ADMIN_CONFIG) {
99	            AdminConfigScreen(onBack = { navController.popBackStack() })
100	        }
101	
102	        composable(Routes.ADMIN_RULES) {
103	            AdminRulesScreen(onBack = { navController.popBackStack() })
104	        }
105	
106	        composable(Routes.ADMIN_ROLLOUTS) {
107	            AdminRolloutsScreen(onBack = { navController.popBackStack() })
108	        }
109	
110	        composable(Routes.ADMIN_USERS) {
111	            AdminUsersScreen(onBack = { navController.popBackStack() })
112	        }
113	
114	        composable(Routes.ADMIN_AUDIT) {
115	            AdminAuditScreen(onBack = { navController.popBackStack() })
116	        }
117	
118	        // ── Agent ──
119	        composable(Routes.AGENT_DASHBOARD) {
120	            AgentDashboardScreen(
121	                onNavigateToTickets = { navController.navigate(Routes.AGENT_TICKETS) },
122	                onLogout = {
123	                    authViewModel.logout()
124	                    navController.navigate(Routes.LOGIN) { popUpTo(0) { inclusive = true } }
125	                }
126	            )
127	        }
128	
129	        composable(Routes.AGENT_TICKETS) {
130	            AgentTicketListScreen(
131	                onTicketClick = { ticketId ->
132	                    navController.navigate("agent/ticket/$ticketId")
133	                },
134	                onBack = { navController.popBackStack() }
135	            )
136	        }
137	
138	        composable(
139	            Routes.AGENT_TICKET_DETAIL,
140	            arguments = listOf(navArgument("ticketId") { type = NavType.StringType })
141	        ) { backStackEntry ->
142	            val ticketId = backStackEntry.arguments?.getString("ticketId") ?: ""
143	            AgentTicketDetailScreen(
144	                ticketId = ticketId,
145	                onBack = { navController.popBackStack() }
146	            )
147	        }
148	
149	        // ── End User ──
150	        composable(Routes.USER_DASHBOARD) {
151	            UserDashboardScreen(
152	                onNavigateToProfile = { navController.navigate(Routes.USER_PROFILE) },
153	                onNavigateToMealPlan = { navController.navigate(Routes.USER_MEAL_PLAN) },
154	                onNavigateToLearningPlans = { navController.navigate(Routes.USER_LEARNING_PLANS) },
155	                onNavigateToMessages = { navController.navigate(Routes.USER_MESSAGES) },
156	                onNavigateToTickets = { navController.navigate(Routes.USER_TICKETS) },
157	                onLogout = {
158	                    authViewModel.logout()
159	                    navController.navigate(Routes.LOGIN) { popUpTo(0) { inclusive = true } }
160	                }
161	            )
162	        }
163	
164	        composable(Routes.USER_PROFILE) {
165	            UserProfileScreen(onBack = { navController.popBackStack() })
166	        }
167	
168	        composable(Routes.USER_MEAL_PLAN) {
169	            UserMealPlanScreen(onBack = { navController.popBackStack() })
170	        }
171	
172	        composable(Routes.USER_LEARNING_PLANS) {
173	            UserLearningPlanScreen(onBack = { navController.popBackStack() })
174	        }
175	
176	        composable(Routes.USER_MESSAGES) {
177	            UserMessagesScreen(onBack = { navController.popBackStack() })
178	        }
179	
180	        composable(Routes.USER_TICKETS) {
181	            UserTicketsScreen(onBack = { navController.popBackStack() })
182	        }
183	    }
184	}
