23	    // ── Config CRUD with versioning ──
24	
25	    suspend fun createConfig(
26	        key: String, value: String, actorId: String, actorRole: Role
27	    ): Result<String> = withContext(Dispatchers.IO) {
28	        try {
29	            val configId = UUID.randomUUID().toString()
30	            val versionId = UUID.randomUUID().toString()
31	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
32	
33	            auditManager.logWithTransaction(
34	                entityType = "Config", entityId = configId,
35	                action = AuditAction.CREATE, actorId = actorId, actorRole = actorRole,
36	                details = """{"key":"$key","version":1}"""
37	            ) {
38	                configQueries.insertConfig(configId, key, value, 1, 1, actorId, now, now)
39	                configQueries.insertConfigVersion(versionId, configId, 1, value, actorId, now)
40	            }
41	
42	            Result.success(configId)
43	        } catch (e: Exception) {
44	            AppLogger.error("ConfigRepo", "Failed to create config", e)
45	            Result.failure(e)
46	        }
47	    }
48	
49	    suspend fun updateConfig(
50	        configId: String, newValue: String, actorId: String, actorRole: Role
51	    ): Result<Unit> = withContext(Dispatchers.IO) {
52	        try {
53	            val config = configQueries.getConfigById(configId).executeAsOneOrNull()
54	                ?: return@withContext Result.failure(IllegalArgumentException("Config not found"))
55	
56	            val newVersion = config.version + 1
57	            val versionId = UUID.randomUUID().toString()
58	            val now = LocalDateTime.now().format(DateTimeFormatter.ISO_LOCAL_DATE_TIME)
59	
60	            auditManager.logWithTransaction(
61	                entityType = "Config", entityId = configId,
62	                action = AuditAction.CONFIG_CHANGE, actorId = actorId, actorRole = actorRole,
63	                previousState = """{"version":${config.version},"value":"${config.configValue}"}""",
64	                newState = """{"version":$newVersion,"value":"$newValue"}"""
65	            ) {
66	                configQueries.updateConfig(newValue, newVersion, 1, now, configId)
67	                configQueries.insertConfigVersion(versionId, configId, newVersion, newValue, actorId, now)
68	            }
69	
70	            Result.success(Unit)
71	        } catch (e: Exception) {
72	            AppLogger.error("ConfigRepo", "Failed to update config", e)
73	            Result.failure(e)
74	        }
75	    }
