3	import androidx.lifecycle.ViewModel
4	import androidx.lifecycle.viewModelScope
5	import com.nutriops.app.domain.usecase.auth.LoginUseCase
6	import com.nutriops.app.security.AuthManager
7	import dagger.hilt.android.lifecycle.HiltViewModel
8	import kotlinx.coroutines.flow.MutableStateFlow
9	import kotlinx.coroutines.flow.StateFlow
10	import kotlinx.coroutines.flow.asStateFlow
11	import kotlinx.coroutines.launch
12	import javax.inject.Inject
13	
14	data class AuthUiState(
15	    val isAuthenticated: Boolean = false,
16	    val needsBootstrap: Boolean = false,
17	    val role: String = "",
18	    val username: String = "",
19	    val error: String? = null,
20	    val isLoading: Boolean = false
21	)
22	
23	@HiltViewModel
24	class AuthViewModel @Inject constructor(
25	    private val loginUseCase: LoginUseCase,
26	    private val authManager: AuthManager
27	) : ViewModel() {
28	
29	    private val _uiState = MutableStateFlow(AuthUiState())
30	    val uiState: StateFlow<AuthUiState> = _uiState.asStateFlow()
31	
32	    init {
33	        checkAuthState()
34	    }
35	
36	    private fun checkAuthState() {
37	        val needsBootstrap = loginUseCase.needsBootstrap()
38	        val session = authManager.currentSession.value
39	        _uiState.value = AuthUiState(
40	            isAuthenticated = session != null,
41	            needsBootstrap = needsBootstrap,
42	            role = session?.role?.name ?: "",
43	            username = session?.username ?: ""
44	        )
45	    }
46	
47	    fun login(username: String, password: String) {
48	        if (username.isBlank() || password.isBlank()) {
49	            _uiState.value = _uiState.value.copy(error = "Username and password are required")
50	            return
51	        }
52	
53	        _uiState.value = _uiState.value.copy(isLoading = true, error = null)
54	
55	        viewModelScope.launch {
56	            when (val result = loginUseCase.login(username, password)) {
57	                is AuthManager.AuthResult.Success -> {
58	                    _uiState.value = AuthUiState(
59	                        isAuthenticated = true,
60	                        role = result.session.role.name,
61	                        username = result.session.username
62	                    )
63	                }
64	                is AuthManager.AuthResult.Failure -> {
65	                    _uiState.value = _uiState.value.copy(isLoading = false, error = result.message)
66	                }
67	                is AuthManager.AuthResult.AccountLocked -> {
68	                    _uiState.value = _uiState.value.copy(isLoading = false, error = "Account is locked. Please try again later.")
69	                }
70	                is AuthManager.AuthResult.NeedsBootstrap -> {
71	                    _uiState.value = _uiState.value.copy(isLoading = false, needsBootstrap = true)
72	                }
73	            }
74	        }
75	    }
76	
77	    fun bootstrap(username: String, password: String) {
78	        if (username.isBlank() || password.length < 8) {
79	            _uiState.value = _uiState.value.copy(error = "Username required, password must be 8+ characters")
80	            return
81	        }
82	
83	        _uiState.value = _uiState.value.copy(isLoading = true, error = null)
84	
85	        viewModelScope.launch {
86	            when (val result = loginUseCase.bootstrap(username, password)) {
87	                is AuthManager.AuthResult.Success -> {
88	                    _uiState.value = AuthUiState(
89	                        isAuthenticated = true,
90	                        role = result.session.role.name,
91	                        username = result.session.username
92	                    )
93	                }
94	                is AuthManager.AuthResult.Failure -> {
95	                    _uiState.value = _uiState.value.copy(isLoading = false, error = result.message)
96	                }
97	                else -> {
98	                    _uiState.value = _uiState.value.copy(isLoading = false, error = "Bootstrap failed")
99	                }
100	            }
101	        }
102	    }
103	
104	    fun logout() {
105	        loginUseCase.logout()
106	        _uiState.value = AuthUiState(needsBootstrap = loginUseCase.needsBootstrap())
107	    }
108	
109	    fun clearError() {
110	        _uiState.value = _uiState.value.copy(error = null)
111	    }
112	}
