import com.google.common.truth.Truth.assertThat
import com.nutriops.app.data.repository.RuleRepository
import com.nutriops.app.domain.model.Role
import io.mockk.*
import kotlinx.coroutines.runBlocking
import org.junit.Before
import org.junit.Test
import java.time.LocalDateTime
import java.time.format.DateTimeFormatter

/**
 * Tests verifying minimum-duration hold, hysteresis behavior,
 * and back-calculation rule-version replay.
 */
class RuleHysteresisDurationTest {

    private val ruleRepository: RuleRepository = mockk(relaxed = true)
    private lateinit var useCase: EvaluateRuleUseCase

    @Before
    fun setup() {
        useCase = EvaluateRuleUseCase(ruleRepository)
    }

    // ── Hysteresis tests ──

    @Test
    fun `hysteresis - entering threshold triggers rule`() {
        val condition = EvaluateRuleUseCase.ConditionNode("metric", "adherence_rate", ">=", 80.0, null)
        val metrics = mapOf("adherence_rate" to 85.0)
        assertThat(useCase.evaluateCondition(condition, metrics)).isTrue()
    }

    @Test
    fun `hysteresis - below enter threshold does not trigger`() {
        val condition = EvaluateRuleUseCase.ConditionNode("metric", "adherence_rate", ">=", 80.0, null)
        val metrics = mapOf("adherence_rate" to 75.0)
        assertThat(useCase.evaluateCondition(condition, metrics)).isFalse()
    }

    @Test
    fun `hysteresis - exactly at threshold triggers for gte operator`() {
        val condition = EvaluateRuleUseCase.ConditionNode("metric", "adherence_rate", ">=", 80.0, null)
        val metrics = mapOf("adherence_rate" to 80.0)
        assertThat(useCase.evaluateCondition(condition, metrics)).isTrue()
    }

    @Test
    fun `hysteresis - not-equal operator works`() {
        val condition = EvaluateRuleUseCase.ConditionNode("metric", "score", "!=", 100.0, null)
        assertThat(useCase.evaluateCondition(condition, mapOf("score" to 99.0))).isTrue()
        assertThat(useCase.evaluateCondition(condition, mapOf("score" to 100.0))).isFalse()
    }

    // ── Minimum-duration hold tests ──

    @Test
    fun `minimum duration - condition first met records hold start`() = runBlocking {
        // Setup: rule with 10-minute minimum duration
        val rule = mockk<Any>(relaxed = true) {
            every { (this@mockk as Any).toString() } returns "rule"
        }

        // When condition is first met but no hold exists, should NOT trigger
        coEvery { ruleRepository.getConditionHold("rule1", "user1") } returns null
