                        metadata = """{"triggered":${eval.triggered},"reason":"${eval.reason}","version":${eval.version}}"""
                    )
                }
            }
        }.onFailure { error ->
            AppLogger.error("RuleWorker", "Rule evaluation failed for user $userId", error)
        }
    }

    companion object {
        const val WORK_NAME = "rule_evaluation"
    }
}
"}

